parameters.jsonBody:
=const item = $('Loop Expirados').item.json;

let tel = String(item.celular).replace(/\D/g, '');
if (!tel.startsWith('55')) tel = '55' + tel;

const body = {
  messaging_product: "whatsapp",
  to: tel,
  type: "template",
  template: {
    name: "novo_anncio_do_produto_que_voc_procura",
    language: { code: "pt_BR" },
    components: [
      {
        type: "body",
        parameters: [
          { type: "text", text: String(item.produto_nome || 'seu produto') }
        ]
      }
    ]
  }
};

return [{
  json: {
    resultado: body,
    telefone: tel,
    whatsapp_number_id: "1123205217553260",
    anuncio_id: item.anuncio_id,
    candidato_id: item.candidato_id,
    score: item.score
  }
}];

